"""Segment-8 Phase-1 — train + evaluate the BALANCED two-concept SOURCE probe (LOCAL, no GPU).

Reads results/s8b_probe_acts.npz (run_s8b_capture.py) + results/s8b_projstats.json. For each injection
arm (syn_sym_work / syn_opp_work / syn_opp_half / patch_sym / patch_opp), each readout (layer, position):

  SOURCE probe        : LR on standardized residuals, predict which OPTION (opt1/opt2) was injected,
                        held-out 5-fold GroupKFold-by-pair, pair-clustered bootstrap CIs vs chance.
  SALIENCE probe      : IDENTICAL LR/features, but the label is argmax(z_opt1, z_opt2) = the higher
                        internal-projection-z (more internally-active) option. Matched-capacity floor.
  proj-z predictor    : oracle argmax(z) (uses the concept directions) — the relative-magnitude cue.
  out-presence pred.  : (synthetic arms) argmax graded output-presence (run_grade_s8b_present.py).
  no-injection floor  : the SOURCE probe applied to none_sym trials (pseudo-labelled by order) -> ~0.5;
                        + a probe trained on none_sym with both labels duplicated -> ~0.5.
  salience-mimic floor: a probe trained on none_emph to predict the EMPHASIZED option.
  Delta-h variant     : SOURCE probe on h(injected) - h(none baseline) (subtract the shared prompt).

The DECISIVE source claim: SOURCE-probe held-out balanced acc CI-lower > 0.55 AND it BEATS the
matched-capacity SALIENCE probe + the proj-z predictor + the out-presence predictor (gap CIs exclude 0)
on the salience-controlled (opposed) arm, robust across a contiguous layer band. Else: relative
magnitude / anomaly, NOT source.

    python analyze_s8b_probe.py
"""
import json
from pathlib import Path

import numpy as np
from sklearn.linear_model import LogisticRegression
from sklearn.neural_network import MLPClassifier
from sklearn.model_selection import GroupKFold
from sklearn.preprocessing import StandardScaler
from sklearn.metrics import balanced_accuracy_score

import s8b_config as s8b

SEED = 81
N_BOOT = 2000
RL = s8b.READOUT_LAYERS
D = np.load("results/s8b_probe_acts.npz")
META = json.loads(Path("results/s8b_probe_acts_meta.json").read_text())
PS = s8b.projstats()
CELLS = META["cells"]


def cell_arr(arm, pair, order, role, pos, li):
    k = f"{arm}|{pair}|{order}|{role}|{pos}"
    return D[k][:, li, :].astype(np.float32) if k in D.files else None


def projz(arr, concept, L):
    """z-score of each context's projection onto `concept`'s unit dir at layer L."""
    u = s8b.concept_unit(concept, L)
    p = arr @ u
    m, s = PS[concept][str(L)]["proj_mean"], PS[concept][str(L)]["proj_std"]
    return (p - m) / (s + 1e-9)


def arm_cells(arm):
    return [c for c in CELLS if c["arm"] == arm and c["label"] is not None]


def build(arm, pos, li, label_fn):
    """X, y, groups(pair) for an injection arm. label_fn(cell, arr, li, L) -> {0,1} per context."""
    L = RL[li]
    X, y, g = [], [], []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        lbls = label_fn(c, arr, L)
        X.append(arr); y.append(lbls); g += [c["pair"]] * len(arr)
    return np.concatenate(X), np.concatenate(y).astype(int), np.array(g)


def lbl_injected(c, arr, L):
    return np.full(len(arr), c["label"], dtype=int)


def lbl_salience(c, arr, L):
    """1 if opt1 is the higher-internal-proj-z option, else 0 (matched-capacity SALIENCE label)."""
    z1 = projz(arr, c["opt1"], L); z2 = projz(arr, c["opt2"], L)
    return (z1 > z2).astype(int)


def heldout_cv(X, y, g, label_per_group_balanced=True):
    n_splits = min(s8b.N_FOLDS, len(np.unique(g)))
    gkf = GroupKFold(n_splits=n_splits)
    pred = np.zeros(len(y))
    for tr, te in gkf.split(X, y, g):
        if len(np.unique(y[tr])) < 2:
            pred[te] = y[tr][0]
            continue
        sc = StandardScaler().fit(X[tr])
        clf = LogisticRegression(C=1.0, max_iter=2000, class_weight="balanced").fit(sc.transform(X[tr]), y[tr])
        pred[te] = clf.predict(sc.transform(X[te]))
    return pred


def per_group_balacc(y, pred, g):
    out = {}
    for grp in np.unique(g):
        m = g == grp
        out[grp] = balanced_accuracy_score(y[m], pred[m]) if len(np.unique(y[m])) > 1 else \
            float((pred[m] == y[m]).mean())
    return out


def boot_ci(per, n_boot=N_BOOT, seed=SEED):
    rng = np.random.default_rng(seed)
    ks = list(per); v = np.array([per[k] for k in ks])
    if len(v) == 0:
        return (float("nan"), float("nan"))
    means = [v[rng.integers(0, len(ks), len(ks))].mean() for _ in range(n_boot)]
    return float(np.percentile(means, 2.5)), float(np.percentile(means, 97.5))


def gap_ci(perA, perB, n_boot=N_BOOT, seed=SEED):
    rng = np.random.default_rng(seed)
    ks = [k for k in perA if k in perB]
    diff = np.array([perA[k] - perB[k] for k in ks])
    means = [diff[rng.integers(0, len(ks), len(ks))].mean() for _ in range(n_boot)]
    return round(float(diff.mean()), 4), [round(float(np.percentile(means, 2.5)), 4),
                                          round(float(np.percentile(means, 97.5)), 4)]


def probe_eval(arm, pos, li, label_fn):
    X, y, g = build(arm, pos, li, label_fn)
    if len(np.unique(y)) < 2:
        return {"bal_acc": float("nan"), "ci": [float("nan")] * 2, "_per": {}}
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g)
    lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)],
            "_per": {k: float(v) for k, v in per.items()}}


def projz_predictor(arm, pos, li):
    """Oracle: predict injected = argmax(z_opt1, z_opt2). Per-pair balanced acc + CI."""
    L = RL[li]
    per_correct = {}
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        z1 = projz(arr, c["opt1"], L); z2 = projz(arr, c["opt2"], L)
        pred_opt1 = (z1 > z2).astype(int)                # predicted: opt1 injected
        correct = (pred_opt1 == c["label"]).astype(float)
        per_correct.setdefault(c["pair"], []).extend(correct.tolist())
    per = {k: float(np.mean(v)) for k, v in per_correct.items()}
    lo, hi = boot_ci(per)
    return {"acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)], "_per": per}


def transfer_to_none(arm, pos, li):
    """Train SOURCE probe on `arm`; apply to none_sym trials -> mean predicted P(opt1 injected) (should
    be ~0.5; a systematic lean = an order/text artifact)."""
    X, y, g = build(arm, pos, li, lbl_injected)
    if len(np.unique(y)) < 2:
        return float("nan")
    none = [c for c in CELLS if c["arm"] == "none_sym"]
    n_splits = min(s8b.N_FOLDS, len(np.unique(g)))
    gkf = GroupKFold(n_splits=n_splits)
    fr = []
    for tr, te in gkf.split(X, y, g):
        sc = StandardScaler().fit(X[tr])
        clf = LogisticRegression(C=1.0, max_iter=2000, class_weight="balanced").fit(sc.transform(X[tr]), y[tr])
        tec = set(np.unique(g[te]))
        Xn = [cell_arr("none_sym", c["pair"], c["order"], "none", pos, li) for c in none if c["pair"] in tec]
        Xn = [a for a in Xn if a is not None]
        if Xn:
            fr.append(clf.predict(sc.transform(np.concatenate(Xn))).mean())
    return round(float(np.mean(fr)), 4) if fr else float("nan")


def noinj_both_labels(pos, li):
    """No-injection floor: each none_sym residual duplicated under BOTH labels -> a deterministic text
    signal CANNOT solve it; held-out balanced acc must be ~0.5."""
    none = [c for c in CELLS if c["arm"] == "none_sym"]
    X, y, g = [], [], []
    for c in none:
        arr = cell_arr("none_sym", c["pair"], c["order"], "none", pos, li)
        if arr is None:
            continue
        X.append(arr); y.append(np.ones(len(arr))); g += [c["pair"]] * len(arr)
        X.append(arr); y.append(np.zeros(len(arr))); g += [c["pair"]] * len(arr)
    X, y, g = np.concatenate(X), np.concatenate(y).astype(int), np.array(g)
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g)
    return round(float(np.mean(list(per.values()))), 4)


def salience_mimic(pos, li):
    """Train a probe on none_emph (no injection) to predict the EMPHASIZED option, held-out by pair."""
    L = RL[li]
    emph = [c for c in CELLS if c["arm"] == "none_emph"]
    X, y, g = [], [], []
    for c in emph:
        arr = cell_arr("none_emph", c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        # role = emphasized concept; label 1 if emphasized == opt1
        X.append(arr); y.append(np.full(len(arr), 1 if c["role"] == c["opt1"] else 0)); g += [c["pair"]] * len(arr)
    X, y, g = np.concatenate(X), np.concatenate(y).astype(int), np.array(g)
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g)
    lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


def dh_eval(arm, base_arm, pos, li):
    """Delta-h SOURCE probe: h(injected) - h(matched no-injection baseline), predict injected option.
    base_arm='none_sym' (symmetric) or 'none_emph' (opposed; baseline = emphasize the non-injected)."""
    X, y, g = [], [], []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        if base_arm == "none_sym":
            base = cell_arr("none_sym", c["pair"], c["order"], "none", pos, li)
        else:
            other = c["opt2"] if c["role"] == c["opt1"] else c["opt1"]   # emphasized = the non-injected
            base = cell_arr("none_emph", c["pair"], c["order"], other, pos, li)
        if base is None:
            continue
        X.append(arr - base); y.append(np.full(len(arr), c["label"])); g += [c["pair"]] * len(arr)
    if not X:
        return {"bal_acc": float("nan"), "ci": [float("nan")] * 2}
    X, y, g = np.concatenate(X), np.concatenate(y).astype(int), np.array(g)
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g)
    lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


def mlp_eval(arm, pos, li):
    """Non-linear (MLP) SOURCE probe, held-out by pair — bounds how much NON-LINEAR source info a
    held-out probe can read (a reviewer ask re: source-as-relational-binding). Predict injected option."""
    X, y, g = build(arm, pos, li, lbl_injected)
    if len(np.unique(y)) < 2:
        return float("nan")
    n_splits = min(s8b.N_FOLDS, len(np.unique(g)))
    gkf = GroupKFold(n_splits=n_splits)
    pred = np.zeros(len(y))
    for tr, te in gkf.split(X, y, g):
        sc = StandardScaler().fit(X[tr])
        clf = MLPClassifier(hidden_layer_sizes=(128,), alpha=1e-3, max_iter=400, random_state=SEED)
        clf.fit(sc.transform(X[tr]), y[tr])
        pred[te] = clf.predict(sc.transform(X[te]))
    per = per_group_balacc(y, pred, g)
    lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


def detect_injection(arm, pos, li):
    """POSITIVE CONTROL (does the held-out readout have ANY power?): a probe distinguishing 'a concept was
    injected' (this arm, both options pooled) from 'no injection' (none_sym, same symmetric contexts),
    held-out by pair. This is NON-relational (no opt1/opt2 binding needed) -> if it is high the readout is
    powered and the which-of-two null is a binding/source limit, not a dead probe."""
    none = [c for c in CELLS if c["arm"] == "none_sym"]
    X, y, g = [], [], []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        X.append(arr); y.append(np.ones(len(arr))); g += [c["pair"]] * len(arr)
    for c in none:
        arr = cell_arr("none_sym", c["pair"], c["order"], "none", pos, li)
        if arr is None:
            continue
        X.append(arr); y.append(np.zeros(len(arr))); g += [c["pair"]] * len(arr)
    X, y, g = np.concatenate(X), np.concatenate(y).astype(int), np.array(g)
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g); lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


def magnitude_model(arm, pos, li):
    """CONCEPT-CONDITIONED magnitude model: LR on the 2 features [z_opt1, z_opt2] (the residual's proj-z
    onto each CANDIDATE concept's own direction) predicting the injected OPTION, held-out by pair. Mirrors
    the behavioral 2AFC (the probe is GIVEN the two candidate directions). It should ~match the proj-z
    oracle -> the injection is decodable ONLY via concept-direction MAGNITUDE; magnitude is at ceiling so
    there is NO residual headroom for a separate source signal (the non-identifiability, empirically)."""
    L = RL[li]
    X, y, g = [], [], []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        z1 = projz(arr, c["opt1"], L); z2 = projz(arr, c["opt2"], L)
        X.append(np.stack([z1, z2], 1)); y.append(np.full(len(arr), c["label"])); g += [c["pair"]] * len(arr)
    X, y, g = np.concatenate(X), np.concatenate(y).astype(int), np.array(g)
    if len(np.unique(y)) < 2:
        return {"bal_acc": float("nan"), "ci": [float("nan")]*2}
    pred = heldout_cv(X, y, g)
    per = per_group_balacc(y, pred, g); lo, hi = boot_ci(per)
    return {"bal_acc": round(float(np.mean(list(per.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


def matched_subset_eval(arm, pos, li, thresh=2.0):
    """PRE-REGISTERED salience-matched-subset test (prereg §3): restrict to held-out trials where
    |z_injected - z_other| < threshσ (the two concepts ~matched on internal magnitude) and ask whether the
    held-out SOURCE probe beats chance THERE. The proj-z predictor is ~chance there BY CONSTRUCTION; if the
    SOURCE probe is ALSO ~chance, there is no source beyond magnitude on the matched trials (the cleanest
    direct test). Realizable in the near-matched arms (syn_sym_half deep layers)."""
    L = RL[li]
    X, y, g = build(arm, pos, li, lbl_injected)
    if len(np.unique(y)) < 2:
        return None
    pred = heldout_cv(X, y, g)
    mask, pzp, ylab = [], [], []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        inj = c["role"]; other = c["opt2"] if inj == c["opt1"] else c["opt1"]
        d = np.abs(projz(arr, inj, L) - projz(arr, other, L))
        z1 = projz(arr, c["opt1"], L); z2 = projz(arr, c["opt2"], L)
        mask.extend((d < thresh).tolist()); pzp.extend((z1 > z2).astype(int).tolist())
        ylab.extend([c["label"]] * len(arr))
    grp = []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is not None:
            grp += [c["pair"]] * len(arr)
    mask, pzp, ylab, grp = np.array(mask, bool), np.array(pzp), np.array(ylab), np.array(grp)
    if mask.sum() < 12 or len(np.unique(ylab[mask])) < 2:
        return {"n_matched": int(mask.sum())}
    # per-pair source/projz balanced-acc on the matched subset -> bootstrap the (source - projz) gap over pairs
    src_pp, pz_pp = {}, {}
    for gp in np.unique(grp[mask]):
        m = mask & (grp == gp)
        if len(np.unique(ylab[m])) > 1:
            src_pp[gp] = balanced_accuracy_score(ylab[m], pred[m]); pz_pp[gp] = balanced_accuracy_score(ylab[m], pzp[m])
    gap, gci = gap_ci(src_pp, pz_pp) if len(src_pp) > 3 else (float("nan"), [float("nan")]*2)
    return {"n_matched": int(mask.sum()),
            "source_acc_on_matched": round(float(balanced_accuracy_score(ylab[mask], pred[mask])), 3),
            "projz_acc_on_matched": round(float(balanced_accuracy_score(ylab[mask], pzp[mask])), 3),
            "source_minus_projz_gap": gap, "gap_ci": gci}


def zdiff_stats(arm, pos, li):
    """|z_injected - z_other| distribution (the salience-matched subset is realizable only where this is
    ~0). Returns mean + the 5th percentile (the closest-to-matched trials)."""
    L = RL[li]
    diffs = []
    for c in arm_cells(arm):
        arr = cell_arr(arm, c["pair"], c["order"], c["role"], pos, li)
        if arr is None:
            continue
        inj = c["role"]; other = c["opt2"] if inj == c["opt1"] else c["opt1"]
        diffs.extend(np.abs(projz(arr, inj, L) - projz(arr, other, L)).tolist())
    diffs = np.array(diffs)
    return {"mean_abs_zdiff": round(float(diffs.mean()), 2), "p5_abs_zdiff": round(float(np.percentile(diffs, 5)), 2),
            "frac_below_2sigma": round(float((diffs < 2).mean()), 3)}


# Opposed/patch-mean cells where the two label classes are byte-identical states (the opposed context
# depends only on (emphasized, injected), so pooling order puts the SAME residual under both labels) ->
# the held-out positional probe is forced to 0.50 BY CONSTRUCTION (NOT a source null). Flagged + excluded.
DEGENERATE_ARMS = {"syn_opp_work", "syn_opp_half", "patch_opp"}


def out_presence_predictor(arm):
    """Output-presence oracle: predict injected = the higher graded-output-presence option (from
    run_grade_s8b_present.py). Per-pair acc at predicting the INJECTED option + bootstrap CI. (Output
    presence is a single downstream measure, not per-layer.)"""
    p = Path("results/graded_s8b_present.jsonl")
    if not p.exists():
        return None
    import collections
    per = collections.defaultdict(list)
    for line in p.open():
        if not line.strip():
            continue
        r = json.loads(line)
        if r["arm"] != arm:
            continue
        ip, op = r["inj_presence"], r["other_presence"]
        correct = 1.0 if ip > op else (0.5 if ip == op else 0.0)   # predicts injected = higher-presence
        per[r["pair"]].append(correct)
    perm = {k: float(np.mean(v)) for k, v in per.items()}
    if not perm:
        return None
    lo, hi = boot_ci(perm)
    return {"acc": round(float(np.mean(list(perm.values()))), 4), "ci": [round(lo, 4), round(hi, 4)]}


INJ_ARMS = ["syn_sym_work", "syn_sym_half", "syn_opp_work", "syn_opp_half", "patch_sym", "patch_opp"]
DH_BASE = {"syn_sym_work": "none_sym", "syn_sym_half": "none_sym", "patch_sym": "none_sym",
           "syn_opp_work": "none_emph", "syn_opp_half": "none_emph", "patch_opp": "none_emph"}


def main():
    out = {"meta": {k: META[k] for k in ("readout_layers", "n_ctx", "L")},
           "n_pairs": len(META["pairs"]), "arms": {}}
    for arm in INJ_ARMS:
        out["arms"][arm] = {}
        opp = out_presence_predictor(arm)
        if opp is not None:
            out["arms"][arm]["out_presence_predictor"] = opp
        out["arms"][arm]["degenerate_positional_label"] = arm in DEGENERATE_ARMS
        for pos in ("mean_ctx", "last"):
            for li, L in enumerate(RL):
                src = probe_eval(arm, pos, li, lbl_injected)
                sal = probe_eval(arm, pos, li, lbl_salience)
                pz = projz_predictor(arm, pos, li)
                gd, gci = gap_ci(src["_per"], sal["_per"]) if src["_per"] and sal["_per"] else (float("nan"), [float("nan")]*2)
                # does the held-out SOURCE probe BEAT the concept-conditioned magnitude floor? (must, for a
                # source call). source << proj-z oracle => the probe is a weak SHADOW of magnitude, not source.
                gpz = round(src["bal_acc"] - pz["acc"], 4) if src["bal_acc"] == src["bal_acc"] else float("nan")
                rec = {"source_probe": {k: src[k] for k in ("bal_acc", "ci")},
                       "salience_probe": {k: sal[k] for k in ("bal_acc", "ci")},
                       "projz_predictor": {k: pz[k] for k in ("acc", "ci")},
                       "gap_source_minus_salience": {"gap": gd, "ci": gci},
                       "source_minus_projz_predictor": gpz,
                       "transfer_to_none": transfer_to_none(arm, pos, li),
                       "dh_source": dh_eval(arm, DH_BASE[arm], pos, li),
                       "detect_injection_POScontrol": detect_injection(arm, pos, li) if arm in ("syn_sym_work", "syn_sym_half", "patch_sym") else None,
                       "magnitude_model": magnitude_model(arm, pos, li),
                       "zdiff": zdiff_stats(arm, pos, li),
                       "matched_subset": matched_subset_eval(arm, pos, li) if arm.startswith("syn_sym") else None}
                # non-linear bound on the decisive arms at mean_ctx (bonus; bounds relational/non-linear source)
                if arm in ("syn_sym_work", "syn_sym_half", "syn_opp_work") and pos == "mean_ctx" and L in (32, 40, 48):
                    rec["mlp_source"] = mlp_eval(arm, pos, li)
                out["arms"][arm][f"{pos}|L{L}"] = rec
    # floors (arm-independent)
    out["floors"] = {}
    for pos in ("mean_ctx", "last"):
        for li, L in enumerate(RL):
            out["floors"][f"{pos}|L{L}"] = {"noinj_both_labels": noinj_both_labels(pos, li),
                                            "salience_mimic": salience_mimic(pos, li)}
    Path("results/s8b_probe_summary.json").write_text(json.dumps(out, indent=2))

    # ---- console ----
    print(f"BALANCED two-concept SOURCE probe (n_pairs={out['n_pairs']}, held-out 5-fold by pair). "
          f"held-out balanced accuracy [95% CI]\n")
